import React from "react";

const Projects = () => {
  const projects = [
    {
      name: "Travel Advisory Platform",
      tech: "React, JavaScript, Google Maps API, REST APIs",
      desc: "Responsive map-based platform with real-time weather overlays, search, and marker filtering.",
    },
    {
      name: "Event Management Data System",
      tech: "SQL, Python, Azure Data Factory, React (JWT auth)",
      desc: "Secure platform with automated pipelines, optimized SQL schema, and high data integrity.",
    },
  ];

  return (
    <section id="projects" className="py-20 px-6">
      <h2 className="text-3xl font-bold text-center mb-8">Projects</h2>
      <div className="grid md:grid-cols-2 gap-6 max-w-5xl mx-auto">
        {projects.map((proj, idx) => (
          <div key={idx} className="bg-white shadow rounded-lg p-6">
            <h3 className="text-xl font-semibold text-purple-700">{proj.name}</h3>
            <p className="text-sm text-gray-500">{proj.tech}</p>
            <p className="mt-2 text-gray-700">{proj.desc}</p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Projects;
